!(function ($) {
  $.fn.appear = function (callback, options) {
    var settings = $.extend(
      { data: undefined, one: true, accX: 0, accY: 0 },
      options,
    );

    return this.each(function () {
      var $element = $(this);

      $element.appeared = false;

      if (!callback) {
        $element.trigger("appear", settings.data);
        return;
      }

      var $window = $(window);
      var check = function () {
        if (!$element.is(":visible")) {
          $element.appeared = false;
          return;
        }

        var scrollLeft = $window.scrollLeft();
        var scrollTop = $window.scrollTop();
        var offset = $element.offset();

        if (!offset) {
          return;
        }

        var left = offset.left;
        var top = offset.top;
        var accX = settings.accX;
        var accY = settings.accY;
        var height = $element.height();
        var width = $element.width();
        var windowHeight = $window.height();
        var windowWidth = $window.width();

        if (
          scrollTop <= top + height + accY &&
          top <= scrollTop + windowHeight + accY &&
          scrollLeft <= left + width + accX &&
          left <= scrollLeft + windowWidth + accX
        ) {
          if (!$element.appeared) {
            $element.trigger("appear", settings.data);
          }
        } else {
          $element.appeared = false;
        }
      };

      var appeared = function () {
        $element.appeared = true;

        if (settings.one) {
          $window.off("scroll", check);
          var index = $.inArray(check, $.fn.appear.checks);
          if (index >= 0) {
            $.fn.appear.checks.splice(index, 1);
          }
        }

        callback.apply(this, arguments);
      };

      if (settings.one) {
        $element.one("appear", settings.data, appeared);
      } else {
        $element.on("appear", settings.data, appeared);
      }

      $window.on("scroll", check);
      $.fn.appear.checks.push(check);
      check();
    });
  };

  $.extend($.fn.appear, {
    checks: [],
    timeout: null,
    checkAll: function () {
      var checks = $.fn.appear.checks;

      for (var i = checks.length - 1; i >= 0; i -= 1) {
        if (typeof checks[i] !== "function") {
          checks.splice(i, 1);
          continue;
        }

        checks[i]();
      }
    },
    run: function () {
      if ($.fn.appear.timeout) {
        clearTimeout($.fn.appear.timeout);
      }

      $.fn.appear.timeout = setTimeout($.fn.appear.checkAll, 20);
    },
  });

  $.each(
    [
      "append",
      "prepend",
      "after",
      "before",
      "attr",
      "removeAttr",
      "addClass",
      "removeClass",
      "toggleClass",
      "remove",
      "css",
      "show",
      "hide",
    ],
    function (_, method) {
      var original = $.fn[method];

      if (!original) {
        return;
      }

      $.fn[method] = function () {
        var result = original.apply(this, arguments);
        $.fn.appear.run();
        return result;
      };
    },
  );
})(jQuery);
